import json, pathlib, collections

# Sample a few project jsonl files to understand their schema
projects = pathlib.Path.home() / '.claude' / 'projects'
sampled = 0
key_counts = collections.Counter()

for proj in sorted(projects.iterdir())[:10]:
    for f in proj.glob('*.jsonl'):
        with open(f, encoding='utf-8', errors='replace') as fh:
            for i, line in enumerate(fh):
                if i > 3: break
                try:
                    obj = json.loads(line)
                    key_counts.update(obj.keys())
                    if sampled < 3:
                        print('KEYS:', list(obj.keys()))
                        # show message type if present
                        if 'type' in obj:
                            print('  type:', obj['type'])
                        if 'message' in obj:
                            msg = obj['message']
                            print('  message keys:', list(msg.keys()) if isinstance(msg, dict) else type(msg))
                            if isinstance(msg, dict) and 'content' in msg:
                                c = msg['content']
                                if isinstance(c, list) and c:
                                    print('  content[0]:', str(c[0])[:150])
                                elif isinstance(c, str):
                                    print('  content:', c[:150])
                        sampled += 1
                        print()
                except: pass
        if sampled >= 3:
            break
    if sampled >= 3:
        break

print('Common top-level keys:', key_counts.most_common(10))
"
